import React, { useState } from 'react';
import axios from 'axios';
import '../assets/styles/MicrosoftTeams.css';

const MicrosoftTeamsButton = () => {
  const [loading, setLoading] = useState(false);
  const [statusMessage, setStatusMessage] = useState('');

  const openTeams = async () => {
    setLoading(true);
    setStatusMessage('');

    try {
      const response = await axios.post('/open-teams');  // Endpoint-ul API care deschide Teams

      if (response.data.success) {
        setStatusMessage('Microsoft Teams deschis cu succes!');
      } else {
        setStatusMessage('Eroare la deschiderea Microsoft Teams.');
      }
    } catch (error) {
      setStatusMessage('A apărut o eroare la conectarea cu serverul.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="teams-button-container">
      <button className="open-teams-btn" onClick={openTeams} disabled={loading}>
        {loading ? 'Se deschide...' : 'Deschide Microsoft Teams'}
      </button>
      {statusMessage && <p>{statusMessage}</p>}
    </div>
  );
};

export default MicrosoftTeamsButton;
